INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-7b850ce6-moex-00006', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-113-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '警察甲在巡邏時，發現棄置在路邊的機車為先前被害人報案失竊之物，
於是陳報檢察官。檢察官命甲予以扣押。在審判中，檢察官提出該贓車
作為證據，證明被告乙的犯罪事實。試問檢察官命警察扣押的機車有無
證據能力？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "115", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00007', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-112-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲因詐欺案件經法院發布通緝，經司法警察乙逮捕而附帶搜索甲之身體，扣
得毒品一小包，乙經查詢得知甲有施用毒品前科，於甲拒絕自行解尿之際，
乙乃將甲帶往醫院委請醫師對甲強制導尿而採取之，並將尿液送請鑑定，得
有尿液呈毒品陽性反應之鑑定報告一份。試問：（每小題25分，共50分）
甲經警逮捕而接受調查時，甲選任律師 A為辯護人，A對司法警察之
詢問甲及命甲自行解尿，不斷異議，司法警察乙乃禁止 A在場。甲及
A對司法警察乙之禁止處分，得如何救濟之？
檢察官依據甲之尿液及鑑定報告而起訴甲犯有施用毒品罪嫌，依目前
最高法院判決的見解，法院應如何判決？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "fa2f5754edaa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "409", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00008', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-112-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲告乙犯傷害罪嫌，經檢察官 A偵查終結，處分不起訴，甲不服而聲請
再議，亦遭高等檢察署檢察長以再議無理由而駁回之。甲再委任律師向
該管法院聲請准許提起自訴，經法院 B、C、D法官組成合議庭，裁定准
許甲提起自訴。甲乃委任律師自訴乙犯傷害罪嫌，經地方法院判決乙傷
害罪刑，乙明示僅以第一審判決未為緩刑之宣告為由，向高等法院提起
上訴。試問：
如檢察官A轉任為法官，A法官、B法官可否參與乙傷害案件之審判？
（20 分）
高等法院對乙之上訴，其審判範圍為何？如乙傷害案件經判決罪刑確
定，乙擬聲請再審，應向何法院聲請再審？B 法官可否參與乙聲請再
審案件之審判？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "fa2f5754edaa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "409", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00009', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲於桃園市持有一級毒品，於桃園市交付給乙。乙後於新北市將毒品售
與不知名之第三人。乙遭警察官員查獲後，循線發現乙的毒品來自於甲。
偵查終結後，新北地檢署的檢察官起訴了乙販賣毒品案件，並以相牽連
管轄為由，起訴了甲的轉讓毒品案件。試問，新北地方法院得否就甲及
乙的案件為實體審判？請附詳細理由說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "4396c4e8214c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00010', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '於偵查中，檢察官認嫌疑人甲有逃亡之虞，報請地檢署檢察長核發通緝
書獲准。於通緝期間，警察官員於路上發現甲，予以逮捕，並在上衣口
袋中發現海洛英一包。請問，在甲的持有毒品案件中，於甲身上發現的
毒品有無證據能力？法院應如何決定？請附詳細理由說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "4396c4e8214c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00011', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '檢察官訊問證人甲時，未告知其若恐因陳述致自己受刑事追訴或處罰，
得拒絕證言。甲在訊問後，做成不利於己的陳述。檢察官偵查後，另外
起訴了甲，並於甲的案件審判中，提出甲以證人身分接受訊問的陳述為
證據，以證明甲的犯罪事實。請問，法院得否以甲的該陳述作為證據，
認定犯罪事實？請附詳細理由說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "4396c4e8214c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00012', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲犯竊盜罪，擔心東窗事發，於是央求乙代其受過。乙一口答應，前往
警察局，佯稱該起竊案是自己犯下。檢察官未察，偵查後，向法院提起
公訴。審判中，法院發現真正的行為人是甲，不是乙。請問法院對於甲、
乙分別應如何處理？請附詳細理由說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "4396c4e8214c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00013', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-359207d9', 'sub-judicial-7b850ce6-02', NULL, 'single_choice', '黃先生回到母校，看見校長室牆上掛滿匾額，下列那一個題辭不適合出現？', '["時雨春風", "澤被三臺", "絃歌盈耳", "功著杏林"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00014', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-359207d9', 'sub-judicial-7b850ce6-02', NULL, 'single_choice', '「愛，是人類生命存在的心靈經驗之一，只有真切地面對自己以及所愛之人內在活生 生的心靈，才能照見彼此不能相愛的障礙而加以克服。然而，他們卻遺忘了自己的 存在，只是不斷地追逐著各種外在的知識，以為這樣就能幸福快樂。」 下列敘述何者最貼近本文的旨趣？', '["知識的追逐讓人們忘了如何相愛", "體認自身之存在為追逐知識之本", "人經常忘記照見自己而產生了相愛的障礙", "相愛的根本在於面對彼此的內心而非知識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00015', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-111-359207d9', 'sub-judicial-7b850ce6-02', NULL, 'single_choice', '「美是一種生命整體存在感的湧現。當此際必然是物我兩忘，情景交融，渾成一片， 而容不下絲毫的分辨與思維。當天邊飛過一抹彩霞，你只合目瞪口呆；連一句『好 美啊』的呢喃，都已是心靈對此境的意識與抽離，也早已構成對美的留戀與破壞。」 根據上文，最符合美的感受是：', '["盡在不言中", "物我保持距離", "感官與意識的交融", "生命主體的思維湧現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "114", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL)
